!function() {
    // Dropdown submenu toggle
    document.querySelectorAll(".dropdown-menu a.dropdown-toggle").forEach(function(el) {
        el.addEventListener("click", function(e) {
            if (!this.nextElementSibling.classList.contains("show")) {
                this.closest(".dropdown-menu").querySelectorAll(".show")
                    .forEach(function(el) { el.classList.remove("show"); });
            }
            this.nextElementSibling.classList.toggle("show");

            const parentDropdown = this.closest("li.nav-item.dropdown.show");
            if (parentDropdown) {
                parentDropdown.addEventListener("hidden.bs.dropdown", function() {
                    document.querySelectorAll(".dropdown-submenu .show")
                        .forEach(function(el) { el.classList.remove("show"); });
                });
            }
            e.stopPropagation();
        });
    });

    // Bootstrap tooltips & popovers
    document.querySelectorAll('[data-bs-toggle="tooltip"]').forEach(function(el) {
        new bootstrap.Tooltip(el);
    });
    document.querySelectorAll('[data-bs-toggle="popover"]').forEach(function(el) {
        new bootstrap.Popover(el);
    });

    // Payment card toggle
    const cardRadioOne = document.querySelector("#cardRadioone"),
          cardRadioTwo = document.querySelector("#cardRadioTwo"),
          internetPayment = document.querySelector("#internetpayment"),
          cardPayment = document.querySelector("#cardpayment");

    if(cardRadioOne && cardRadioTwo) {
        internetPayment.style.display = "none";

        cardRadioOne.addEventListener("change", function() {
            if(this.checked) {
                cardPayment.style.display = "";
                internetPayment.style.display = "none";
            }
        });
        cardRadioTwo.addEventListener("change", function() {
            if(this.checked) {
                internetPayment.style.display = "";
                cardPayment.style.display = "none";
            }
        });
    }

    // Password strength indicator
    document.querySelectorAll(".password-field input").forEach(function(el) {
        el.addEventListener("keyup", function() {
            const strength = function(val) {
                let score = 0;
                if(val.length >= 6) score += 1;
                if(/([a-z].*[A-Z])|([A-Z].*[a-z])/.test(val)) score += 1;
                if(/[a-zA-Z]/.test(val) && /[0-9]/.test(val)) score += 1;
                return score;
            }(this.value);

            let parent = this.parentElement;
            parent.classList.remove(...parent.classList);
            parent.classList.add("password-field", "level"+strength);
        });
    });

    // Sidebar toggle
    const navToggle = document.getElementById("nav-toggle"),
          dbWrapper = document.getElementById("db-wrapper");

    if(navToggle && dbWrapper) {
        navToggle.addEventListener("click", function(e) {
            e.preventDefault();
            dbWrapper.classList.toggle("toggled");
        });
    }

    // Print invoice
    const invoice = document.getElementById("invoice");
    if(invoice) {
        invoice.querySelector(".print-link").addEventListener("click", function() {
            window.print();
        });
    }

    // Sidebar nav smooth scroll + active class
    document.querySelectorAll(".sidebar-nav-fixed a").forEach(function(el) {
        el.addEventListener("click", function(e) {
            if(location.pathname.replace(/^\//,"") === this.pathname.replace(/^\//,"")
               && location.hostname === this.hostname) {
                let target = document.querySelector(this.hash) || 
                             document.querySelector("[name="+this.hash.slice(1)+"]");
                if(target) {
                    e.preventDefault();
                    window.scrollTo({top: target.offsetTop-90, behavior:"smooth"});
                    target.setAttribute("tabindex","-1");
                    target.focus();
                }
            }
            document.querySelectorAll(".sidebar-nav-fixed a").forEach(function(a){a.classList.remove("active");});
            this.classList.add("active");
        });
    });

    // Checkbox "check all"
    const checkAll = document.querySelector("#checkAll");
    if(checkAll) {
        checkAll.addEventListener("click", function() {
            document.querySelectorAll('input[type="checkbox"]').forEach(function(checkbox){
                if(checkbox !== checkAll) checkbox.checked = checkAll.checked;
            });
        });
    }

    // Button icon active class
    document.querySelectorAll("#btn-icon .btn-icon").forEach(function(btn) {
        btn.addEventListener("click", function() {
            btn.parentElement.classList.add("active");
            Array.from(btn.parentElement.parentNode.children)
                 .filter(el => el !== btn.parentElement)
                 .forEach(el => el.classList.remove("active"));
        });
    });

    // Stop event propagation
    document.querySelectorAll(".stopevent").forEach(function(el) {
        el.addEventListener("click", function(e){ e.stopPropagation(); });
    });

    // Tagify initialization
    const tagsInput = document.querySelector("input[name=tags]");
    if(tagsInput) new Tagify(tagsInput);

    // Form validation
    document.querySelectorAll(".needs-validation").forEach(function(form) {
        form.addEventListener("submit", function(e) {
            if(!form.checkValidity()) {
                e.preventDefault();
                e.stopPropagation();
            }
            form.classList.add("was-validated");
        }, false);
    });

    // Bootstrap toasts and offcanvas
    document.querySelectorAll(".toast").forEach(function(el){ new bootstrap.Toast(el); });
    document.querySelectorAll(".offcanvas").forEach(function(el){ new bootstrap.Offcanvas(el); });
    document.querySelectorAll(".dropdown-toggle").forEach(function(el){ new bootstrap.Dropdown(el); });

    // Live alert button
    const liveAlertPlaceholder = document.getElementById("liveAlertPlaceholder"),
          liveAlertBtn = document.getElementById("liveAlertBtn");

    if(liveAlertPlaceholder && liveAlertBtn) {
        liveAlertBtn.addEventListener("click", function() {
            const div = document.createElement("div");
            div.innerHTML = `
                <div class="alert alert-success alert-dismissible" role="alert">
                    Nice, you triggered this alert message!
                    <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>
                </div>
            `;
            liveAlertPlaceholder.appendChild(div);
        });
    }

    // NoUI sliders example
    const slider = document.getElementById("slider");
    if(slider) noUiSlider.create(slider, {start:[32], connect:[true,false], range:{min:0,max:60}, tooltips:[wNumb({decimals:0})]});

    // Scroll top button
    const btnScrollTop = document.querySelector(".btn-scroll-top");
    if(btnScrollTop) {
        const path = btnScrollTop.querySelector("path"),
              length = path.getTotalLength();

        path.style.transition = path.style.WebkitTransition = "none";
        path.style.strokeDasharray = length+" "+length;
        path.style.strokeDashoffset = length;

        path.getBoundingClientRect();
        path.style.transition = path.style.WebkitTransition = "stroke-dashoffset 10ms linear";

        window.addEventListener("scroll", function() {
            const scroll = document.body.scrollTop || document.documentElement.scrollTop,
                  maxScroll = document.documentElement.scrollHeight - document.documentElement.clientHeight,
                  offset = length - scroll*length/maxScroll;

            path.style.strokeDashoffset = offset;

            if(scroll >= 50) btnScrollTop.classList.add("active-progress");
            else btnScrollTop.classList.remove("active-progress");
        });

        btnScrollTop.addEventListener("click", function(e) {
            e.preventDefault();
            window.scroll({top:0,left:0,behavior:"smooth"});
        });
    }

    // Price & experience range sliders
    const priceRange = document.getElementById("priceRange"),
          priceRangeValue = document.getElementById("priceRange-value"),
          expRange = document.getElementById("expRange"),
          expRangeValue = document.getElementById("expRange-value");

    if(priceRange){
        noUiSlider.create(priceRange,{
            connect:true,
            behaviour:"tap",
            start:[0,1500],
            step:200,
            range:{min:[0], max:[1500]},
            format:wNumb({prefix:"$"})
        });
        priceRange.noUiSlider.on("update", function(values){ priceRangeValue.innerHTML = values.join(" - "); });
    }

    if(expRange){
        noUiSlider.create(expRange,{
            connect:true,
            behaviour:"tap",
            start:[0,15],
            step:1,
            range:{min:0,max:15},
            format:wNumb({})
        });
        expRange.noUiSlider.on("update", function(values){ expRangeValue.innerHTML = values.join(" - "); });
    }

}();

// Changelog example
const changelogElement = document.getElementById("changelog");
if(changelogElement){
    function changeLog(){ changelogElement.innerHTML = "v3.3.1"; }
    changeLog();
}
